SELECT u.*, auth.auth, ua.full_Address, r.user_id AS referrer_id FROM ( /* 1. 검색과 페이징이 적용된 핵심 유저 추출 */ SELECT usr.id, usr.user_id, usr.user_nm, usr.email, usr.phone_num, usr.address_id, usr.point_id, usr.referrer_no, usr.guard_type, usr.role, usr.is_stopped, usr.created_at, usr.phone_hash, /* 포인트 합계 (스칼라 서브쿼리가 조인보다 안전하고 빠릅니다) */ (SELECT COALESCE(SUM(amount), 0) FROM point_history WHERE user_id = usr.id AND settlement_status = 'READY' AND is_deleted = 'N') AS pending_point, (CASE WHEN usr.guard_type = '00' THEN '스텝' WHEN usr.guard_type = '01' THEN '경호원 신청 중' WHEN usr.guard_type = '02' THEN '경호원' WHEN usr.guard_type = '03' THEN '수행' WHEN usr.guard_type = '04' THEN '인솔자' ELSE '미지정' END) AS guard_type_nm FROM user usr WHERE usr.is_deleted = 'N' AND usr.role != 'Admin'
/* 검색 조건은 안쪽에서 처리해야 페이징이 정확합니다 */
AND
(usr.user_id LIKE CONCAT('%', #{option.keyword}, '%') OR usr.user_nm LIKE CONCAT('%', #{option.keyword}, '%') OR usr.email LIKE CONCAT('%', #{option.keyword}, '%'))
usr.user_id LIKE CONCAT('%', #{option.keyword}, '%') usr.user_nm LIKE CONCAT('%', #{option.keyword}, '%') usr.email LIKE CONCAT('%', #{option.keyword}, '%') usr.phone_hash = #{option.keyword} usr.guard_type = #{option.keyword} usr.is_stopped = #{option.keyword}
/* 정렬 기준 */
ORDER BY usr.point_id DESC, usr.id DESC ORDER BY usr.referrer_no ASC, usr.id DESC ORDER BY usr.guard_type ASC, usr.id DESC ORDER BY usr.id DESC
/* 페이징 처리 */ LIMIT #{page.index}, #{page.rows} ) u /* 2. 페이징된 결과에 대해서만 부가 정보 조인 */ LEFT OUTER JOIN user_address ua ON ua.address_id = u.address_id LEFT OUTER JOIN user_auth auth ON u.id = auth.no LEFT OUTER JOIN user r ON u.referrer_no = r.id
/* 추천인 검색(code 4)은 조인된 결과에서 필터링이 필요할 수 있으나 성능상 위 구조를 유지하는 것이 좋습니다 */
WHERE r.user_id LIKE CONCAT('%', #{option.keyword}, '%')

